-- ============================================================
-- WAI System Database - Uitgebreide versie
-- MariaDB / HeidiSQL importbestand
-- 65 gebruikers, waarvan 50 actieve users
-- Gebieden: Paramaribo en Wanica
-- ============================================================

DROP DATABASE IF EXISTS wai_system_db;
CREATE DATABASE wai_system_db
    CHARACTER SET utf8mb4
    COLLATE utf8mb4_unicode_ci;

USE wai_system_db;

CREATE TABLE users (
    user_id INT AUTO_INCREMENT PRIMARY KEY,
    full_name VARCHAR(100) NOT NULL,
    email VARCHAR(120) NOT NULL UNIQUE,
    password_hash VARCHAR(255) NOT NULL,
    phone VARCHAR(30),
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    status ENUM('active','inactive') DEFAULT 'active'
);

CREATE TABLE households (
    household_id INT AUTO_INCREMENT PRIMARY KEY,
    user_id INT NOT NULL,
    address VARCHAR(180) NOT NULL,
    district ENUM('Paramaribo','Wanica') NOT NULL,
    number_of_residents INT DEFAULT 1,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_households_users
        FOREIGN KEY (user_id) REFERENCES users(user_id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
);

CREATE TABLE wai_systems (
    system_id INT AUTO_INCREMENT PRIMARY KEY,
    household_id INT NOT NULL,
    system_name VARCHAR(100) NOT NULL,
    installation_date DATE,
    status ENUM('active','maintenance','inactive') DEFAULT 'active',
    notes TEXT,
    CONSTRAINT fk_systems_households
        FOREIGN KEY (household_id) REFERENCES households(household_id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
);

CREATE TABLE water_tanks (
    tank_id INT AUTO_INCREMENT PRIMARY KEY,
    system_id INT NOT NULL,
    tank_name VARCHAR(100) NOT NULL,
    capacity_liters DECIMAL(10,2) NOT NULL,
    current_level_liters DECIMAL(10,2) DEFAULT 0,
    location VARCHAR(120),
    status ENUM('normal','low','critical','maintenance') DEFAULT 'normal',
    CONSTRAINT fk_tanks_systems
        FOREIGN KEY (system_id) REFERENCES wai_systems(system_id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
);

CREATE TABLE water_level_history (
    water_reading_id INT AUTO_INCREMENT PRIMARY KEY,
    tank_id INT NOT NULL,
    reading_datetime DATETIME NOT NULL,
    water_level_liters DECIMAL(10,2) NOT NULL,
    water_level_percent DECIMAL(5,2) NOT NULL,
    daily_usage_liters DECIMAL(10,2) DEFAULT 0,
    status ENUM('good','warning','critical') DEFAULT 'good',
    CONSTRAINT fk_water_history_tanks
        FOREIGN KEY (tank_id) REFERENCES water_tanks(tank_id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
);

CREATE TABLE energy_history (
    energy_reading_id INT AUTO_INCREMENT PRIMARY KEY,
    system_id INT NOT NULL,
    reading_datetime DATETIME NOT NULL,
    energy_generated_wh DECIMAL(10,2) DEFAULT 0,
    battery_level_percent DECIMAL(5,2) DEFAULT 0,
    status ENUM('good','warning','critical') DEFAULT 'good',
    CONSTRAINT fk_energy_history_systems
        FOREIGN KEY (system_id) REFERENCES wai_systems(system_id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
);

CREATE TABLE services (
    service_id INT AUTO_INCREMENT PRIMARY KEY,
    service_name VARCHAR(100) NOT NULL,
    description TEXT,
    base_price DECIMAL(10,2) DEFAULT 0,
    active TINYINT(1) DEFAULT 1
);

CREATE TABLE service_requests (
    request_id INT AUTO_INCREMENT PRIMARY KEY,
    user_id INT NOT NULL,
    system_id INT NOT NULL,
    service_id INT NOT NULL,
    request_date DATE NOT NULL,
    preferred_date DATE,
    description TEXT,
    status ENUM('pending','approved','in_progress','completed','cancelled') DEFAULT 'pending',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_requests_users
        FOREIGN KEY (user_id) REFERENCES users(user_id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_requests_systems
        FOREIGN KEY (system_id) REFERENCES wai_systems(system_id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_requests_services
        FOREIGN KEY (service_id) REFERENCES services(service_id)
        ON DELETE RESTRICT
        ON UPDATE CASCADE
);

CREATE TABLE notifications (
    notification_id INT AUTO_INCREMENT PRIMARY KEY,
    user_id INT NOT NULL,
    system_id INT NOT NULL,
    title VARCHAR(150) NOT NULL,
    message TEXT NOT NULL,
    type ENUM('info','warning','critical','service') DEFAULT 'info',
    is_read TINYINT(1) DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_notifications_users
        FOREIGN KEY (user_id) REFERENCES users(user_id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_notifications_systems
        FOREIGN KEY (system_id) REFERENCES wai_systems(system_id)
        ON DELETE CASCADE
        ON UPDATE CASCADE
);

CREATE TABLE maintenance_logs (
    maintenance_id INT AUTO_INCREMENT PRIMARY KEY,
    system_id INT NOT NULL,
    service_id INT NOT NULL,
    maintenance_date DATE NOT NULL,
    performed_by VARCHAR(100),
    notes TEXT,
    next_due_date DATE,
    CONSTRAINT fk_maintenance_systems
        FOREIGN KEY (system_id) REFERENCES wai_systems(system_id)
        ON DELETE CASCADE
        ON UPDATE CASCADE,
    CONSTRAINT fk_maintenance_services
        FOREIGN KEY (service_id) REFERENCES services(service_id)
        ON DELETE RESTRICT
        ON UPDATE CASCADE
);

